                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <CompactCounter label="Bilmece Adedi" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={1} max={12} icon="fa-hashtag" />
                        <CompactToggleGroup 
