                        />
                    )}

                    {isSymmetry && (
                        <CompactToggleGroup 
                            label="Simetri Ekseni" 
                            selected={options.visualType || 'vertical'} 
                            onChange={(v: string) => handleChange('visualType', v)} 
                            options={[{ value: 'vertical', label: 'DİKEY' }, { value: 'horizontal', label: 'YATAY' }]} 
