import { Type } from "@google/genai";
import { generateWithSchema } from '../geminiClient';
import { GeneratorOptions, AbcConnectData } from '../../types';

const PEDAGOGICAL_PROMPT = `
[ROL: KIDEMLİ ÖZEL EĞİTİM UZMANI & GÖRSEL ALGI TERAPİSTİ]
GÖREV: Disleksik çocuklar için sekansel dikkati ve görsel taramayı güçlendiren "ABC Bağlamaca" etkinliği üret.
`;

export const generateAbcConnectFromAI = async (options: GeneratorOptions): Promise<AbcConnectData[]> => {
    const { difficulty, worksheetCount, variant = 'alphabetic', itemCount = 10 } = options;

    const variantDesc = {
        'alphabetic': 'A-Z alfabetik sıra (Disleksi fontu ile).',
        'numeric': '1-20 sayısal sıra (Sayı sembolizmi takibi).',
        'words': 'Birbiriyle semantik ilişkili kelimeler (Örn: Elma -> Meyve -> Portakal).',
        'visuals': 'Nesne görselleri ve onların isimlerinin baş harfleri.'
    }[variant as string] || 'Harfler';

    const prompt = `
    ${PEDAGOGICAL_PROMPT}
    ZORLUK: ${difficulty}
    VARYANT: ${variantDesc}
    ADET: Sayfa başına ${itemCount} düğüm (node).

    KURALLAR:
    1. Her düğümün bir 'label' değeri (A, B, C veya 1, 2, 3 veya Kelime) olmalıdır.
    2. 'points' listesinde her düğümün X ve Y koordinatları (0-100 arası) olmalıdır. 
    3. Koordinatlar birbirine çok yakın olmamalı, kağıda dengeli dağılmalıdır.
    4. ${variant === 'visuals' ? "Her nokta için 'imagePrompt' (İngilizce nesne adı) ekle." : ""}
    5. Disleksi Dostu: Yazı tipi olarak 'OpenDyslexic' baz alınacak.

    ÇIKTI: JSON formatında bir dizi.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.NUMBER },
                            gridDim: { type: Type.NUMBER },
                            points: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        label: { type: Type.STRING },
                                        x: { type: Type.NUMBER },
                                        y: { type: Type.NUMBER },
                                        color: { type: Type.STRING },
                                        imagePrompt: { type: Type.STRING }
                                    },
                                    required: ['label', 'x', 'y']
                                }
                            }
                        },
                        required: ['points']
                    }
                }
            },
            required: ['title', 'instruction', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema) as Promise<AbcConnectData[]>;
};
