import { GeneratorOptions, AbcConnectData } from '../../types';
import { shuffle, getRandomInt, getRandomItems, turkishAlphabet } from './helpers';

export const generateOfflineAbcConnect = async (options: GeneratorOptions): Promise<AbcConnectData[]> => {
    const { worksheetCount, difficulty, variant = 'alphabetic', itemCount = 10 } = options;

    const nodeCount = difficulty === 'Başlangıç' ? 8 : (difficulty === 'Orta' ? 12 : 20);

    return Array.from({ length: worksheetCount }, () => {
        const points = [];
        const alphabet = turkishAlphabet.toLocaleUpperCase('tr').split('');
        const numbers = Array.from({length: nodeCount}, (_, i) => (i + 1).toString());
        const words = shuffle(['KEDİ', 'KÖPEK', 'KUŞ', 'BALIK', 'AT', 'FİL', 'AYI', 'TAVŞAN', 'ASLAN', 'KAPLAN']).slice(0, nodeCount);

        const labels = variant === 'alphabetic' ? alphabet.slice(0, nodeCount)
                    : variant === 'numeric' ? numbers
                    : words;

        // Generate non-overlapping random points
        for (let i = 0; i < labels.length; i++) {
            points.push({
                label: labels[i],
                x: getRandomInt(10, 90),
                y: getRandomInt(10, 90),
                color: '#000000'
            });
        }

        return {
            title: "ABC Bağlamaca",
            instruction: variant === 'numeric' ? "Sayıları 1'den başlayarak sırasıyla birleştirin." : "Harfleri alfabetik sıraya göre takip ederek birleştirin.",
            pedagogicalNote: "Ardışıl işlemleme, görsel tarama hızı ve el-göz koordinasyonu gelişimini destekler.",
            puzzles: [{
                id: Date.now(),
                gridDim: 100,
                points
            }]
        };
    });
};
