interface GeneratorViewProps {
    activity: Activity;
    onGenerate: (options: GeneratorOptions) => void;
    onBack: () => void;
    isLoading: boolean;
    isExpanded?: boolean;
    onOpenStudentModal?: () => void;
    studentProfile?: StudentProfile;
}

const CompactSelect = ({ label, value, onChange, options, icon }: any) => (
    <div className="space-y-1.5">
        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
            {icon && <i className={`fa-solid ${icon}`}></i>} {label}
        </label>
        <select 
            value={value} 
            onChange={(e) => onChange(e.target.value)}
            className="w-full bg-white dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-700 rounded-xl p-2.5 text-xs font-bold outline-none focus:ring-2 ring-indigo-500/20"
        >
            {options.map((opt: any) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
        </select>
    </div>
);

const CompactSlider = ({ label, value, onChange, min, max, icon }: any) => (
    <div className="space-y-1.5">
        <div className="flex justify-between items-center">
            <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
                {icon && <i className={`fa-solid ${icon}`}></i>} {label}
            </label>
            <span className="text-[10px] font-mono font-bold text-indigo-600">{value}</span>
        </div>
        <input type="range" min={min} max={max} value={value} onChange={(e) => onChange(Number(e.target.value))} className="w-full h-1 bg-zinc-200 dark:bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-indigo-600" />
    </div>
);

const CompactToggleGroup = ({ label, selected, onChange, options }: any) => (
    <div className="space-y-1.5">
        <label className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">{label}</label>
        <div className="flex bg-white dark:bg-zinc-900 p-1 rounded-xl border border-zinc-200 dark:border-zinc-700">
            {options.map((opt: any) => (
                <button 
                    key={opt.value} 
                    onClick={() => onChange(opt.value)}
                    className={`flex-1 py-1.5 text-[9px] font-black uppercase rounded-lg transition-all ${selected === opt.value ? 'bg-indigo-600 text-white shadow-sm' : 'text-zinc-400 hover:text-zinc-600'}`}
                >
                    {opt.label}
                </button>
            ))}
        </div>
    </div>
);

export const GeneratorView: React.FC<GeneratorViewProps> = ({ 
    activity, onGenerate, onBack, isLoading, isExpanded, onOpenStudentModal, studentProfile 
}) => {
    const [options, setOptions] = useState<any>({
        mode: 'ai',
        difficulty: 'Orta',
        worksheetCount: 1,
        itemCount: 12,
        topic: 'Genel',
        variant: 'alphabetic',
        fontFamily: 'OpenDyslexic'
    });

    const handleChange = (key: string, value: any) => setOptions((prev: any) => ({ ...prev, [key]: value }));

    const renderActivityControls = () => {
        // --- ABC CONNECT ---
        if (activity.id === ActivityType.ABC_CONNECT) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="İçerik Akışı" 
                        value={options.variant || 'alphabetic'} 
                        onChange={(v:any) => handleChange('variant', v)}
                        options={[
                            { value: 'alphabetic', label: 'Alfabetik (A-B-C)' },
                            { value: 'numeric', label: 'Sayısal (1-2-3)' },
                            { value: 'words', label: 'Kelime Takibi (Semantik)' },
                            { value: 'visuals', label: 'Görsel Eşleme (Resim-Harf)' }
                        ]}
                        icon="fa-route"
                    />

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactSlider label="Nokta Sayısı" value={options.itemCount || 12} onChange={(v:number) => handleChange('itemCount', v)} min={6} max={26} icon="fa-circle-dot" />
                        <CompactToggleGroup 
                            label="Yazı Tipi" 
                            selected={options.fontFamily || 'OpenDyslexic'} 
                            onChange={(v: string) => handleChange('fontFamily', v)} 
                            options={[{ value: 'OpenDyslexic', label: 'DİSLEKSİ' }, { value: 'Lexend', label: 'SADE' }]} 
                        />
                    </div>
                </div>
            );
        }
        return <div className="text-xs text-zinc-400 italic">Bu etkinlik için özel ayar bulunmuyor.</div>;
    };

    return (
        <div className="flex flex-col h-full bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-800">
            <div className="p-4 border-b border-zinc-200 dark:border-zinc-800 flex items-center justify-between bg-zinc-50/50 dark:bg-zinc-800/50">
                <button onClick={onBack} className="w-8 h-8 rounded-full hover:bg-zinc-200 dark:hover:bg-zinc-700 flex items-center justify-center transition-colors text-zinc-500">
                    <i className="fa-solid fa-arrow-left"></i>
                </button>
                <h3 className="font-bold text-sm truncate px-4">{activity.title}</h3>
                <div className="w-8"></div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">
                {renderActivityControls()}
            </div>

            <div className="p-4 border-t border-zinc-200 dark:border-zinc-800 bg-zinc-50/50 dark:bg-zinc-800/50">
                <button 
                    onClick={() => onGenerate(options)} 
                    disabled={isLoading}
                    className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-xl shadow-lg transition-all active:scale-95 disabled:opacity-50"
                >
                    {isLoading ? <i className="fa-solid fa-circle-notch fa-spin mr-2"></i> : <i className="fa-solid fa-wand-magic-sparkles mr-2"></i>}
                    {isLoading ? 'ÜRETİLİYOR...' : 'ETKİNLİĞİ ÜRET'}
                </button>
            </div>
        </div>
    );
};

import React from 'react';
import { ActivityType } from '../types';
