interface SheetRendererProps {
    activityType: ActivityType;
    data: any;
}

export const SheetRenderer: React.FC<SheetRendererProps> = ({ activityType, data }) => {
    switch (activityType) {
        case ActivityType.ABC_CONNECT: return <Visual.AbcConnectSheet data={data} />;
        case ActivityType.READING_SUDOKU: return <Reading.ReadingSudokuSheet data={data} />;
        case ActivityType.READING_STROOP: return <Reading.ReadingStroopSheet data={data} />;
        case ActivityType.NUMBER_LOGIC_RIDDLES: return <NumberLogicRiddleSheet data={data} />;
        case ActivityType.MATH_PUZZLE: return <MathLogic.MathPuzzleSheet data={data} />;
        case ActivityType.STORY_COMPREHENSION: return <Reading.StoryComprehensionSheet data={data} />;
        case ActivityType.HIDDEN_PASSWORD_GRID: return <WordGames.HiddenPasswordGridSheet data={data} />;
        case ActivityType.SYLLABLE_WORD_BUILDER: return <NewActivities.SyllableWordBuilderSheet data={data} />;
        case ActivityType.LETTER_VISUAL_MATCHING: return <Dyslexia.LetterVisualMatchingSheet data={data} />;
        case ActivityType.SYNONYM_ANTONYM_MATCH: return <Reading.SynonymAntonymMatchSheet data={data} />;
        case ActivityType.NUMBER_PATTERN: return <MathLogic.NumberPatternSheet data={data} />;
        case ActivityType.ALGORITHM_GENERATOR: return <MathLogic.FutoshikiSheet data={data} />; // Placeholder
        default: return <div className="p-8 text-center text-zinc-400 italic">Bu etkinlik türü henüz desteklenmiyor ({activityType}).</div>;
    }
};

import React from 'react';
import { AbcConnectData } from '../../types';
import { PedagogicalHeader, ImageDisplay } from './common';
import { EditableText } from '../Editable';

export const AbcConnectSheet: React.FC<{ data: AbcConnectData }> = ({ data }) => {
    const puzzle = data.puzzles[0]; // Sayfa başına 1 büyük puzzle

    return (
        <div className="flex flex-col h-full bg-white font-lexend text-black relative">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} />

            <div className="flex-1 relative mt-10 border-[6px] border-zinc-900 rounded-[3rem] bg-white overflow-hidden shadow-2xl group">
                {/* Drawing Surface Background */}
                <div className="absolute inset-0 opacity-5 pointer-events-none" style={{backgroundImage: 'radial-gradient(#000 1.5px, transparent 1.5px)', backgroundSize: '30px 30px'}}></div>

                <svg viewBox="0 0 100 100" className="w-full h-full p-12 overflow-visible">
                    {/* Nodes */}
                    {(puzzle.points || []).map((point, idx) => (
                        <g key={idx} transform={`translate(${point.x}, ${point.y})`}>
                            {/* Hitbox/Circle */}
                            <circle r="3.5" fill="white" stroke="black" strokeWidth="1" className="drop-shadow-sm" />
                            <circle r="0.8" fill="black" />

                            {/* Label */}
                            <text 
                                y="-6" 
                                textAnchor="middle" 
                                fontSize="4.5" 
                                fontWeight="900" 
                                className="fill-zinc-900 font-dyslexic tracking-tighter"
                                style={{ paintOrder: 'stroke', stroke: 'white', strokeWidth: '1.5px' }}
                            >
                                <EditableText value={point.label} tag="tspan" />
                            </text>

                            {/* Image Placeholder (for visuals variant) */}
                            {point.imagePrompt && (
                                <foreignObject x="-4" y="2" width="8" height="8">
                                    <div className="w-full h-full opacity-20 group-hover:opacity-100 transition-opacity">
                                        <ImageDisplay prompt={point.imagePrompt} className="w-full h-full" />
                                    </div>
                                </foreignObject>
                            )}
                        </g>
                    ))}
                </svg>

                {/* Start/End Indicators */}
