            }));
            setLayout(newLayout);
            setIsSaved(false);
        }
    };

    const deleteTemplate = (id: string) => {
         if(confirm("Şablonu silmek istediğinize emin misiniz?")) {
            const updated = templates.filter(t => t.id !== id);
            setTemplates(updated);
