const RichContentRenderer = ({ data }: { data: any }) => {
    return (
        <div className="space-y-10 w-full animate-in fade-in duration-700">
            <PedagogicalHeader title={data.title} instruction={data.instruction} note={data.pedagogicalNote} data={data} />
            <div className="flex flex-col gap-8">
                {(data.sections || []).map((section: any, idx: number) => (
                    <EditableElement key={idx} className="bg-white rounded-[2.5rem] border-2 border-zinc-100 shadow-sm p-6">
                        <h4 className="text-xs font-black text-indigo-500 uppercase tracking-[0.2em] mb-4 border-b border-indigo-50 pb-2">
                             <EditableText value={section.title} tag="span" />
                        </h4>
                        <div className="text-zinc-800 leading-relaxed font-dyslexic text-lg"><EditableText value={section.content} tag="div" /></div>
                    </EditableElement>
                ))}
            </div>
        </div>
    );
};

export const SheetRenderer = React.memo(({ activityType, data }: SheetRendererProps) => {
    if (!data) return null;

    if (activityType === ActivityType.ABC_CONNECT) return <Visual.AbcConnectSheet data={data} />;

    if (activityType === ActivityType.AI_WORKSHEET_CONVERTER || activityType === ActivityType.OCR_CONTENT || data.sections) {
        return <RichContentRenderer data={data} />;
    }

    if (activityType === ActivityType.STORY_COMPREHENSION && data.layout) {
        return <ReadingStudioContentRenderer layout={data.layout} storyData={data.storyData} />;
    }

    if (activityType === ActivityType.ALGORITHM_GENERATOR) {
        return <AlgorithmSheet data={data} />;
    }

    switch (activityType) {
        case ActivityType.READING_SUDOKU: return <Reading.ReadingSudokuSheet data={data} />;
        case ActivityType.READING_STROOP: return <Reading.ReadingStroopSheet data={data} />;
        case ActivityType.SYNONYM_ANTONYM_MATCH: return <Reading.SynonymAntonymMatchSheet data={data} />;
        case ActivityType.LETTER_VISUAL_MATCHING: return <Dyslexia.LetterVisualMatchingSheet data={data} />;
