export const generateAbcConnectFromAI = async (options: GeneratorOptions): Promise<AbcConnectData[]> => {
    const { difficulty, worksheetCount, variant = 'alphabetic', itemCount = 12 } = options;

    const prompt = `
    [GÖREV: ABC BAĞLAMACA (DOT-TO-DOT) PROFESYONEL ETKİNLİK]
    GÖREV: Disleksik çocuklar için "${difficulty}" seviyesinde bir bağlama etkinliği üret.
    VARYANT: ${variant} (Seçenekler: alphabetic, numeric, words, visuals)
    ADET: Sayfa başına ${itemCount} nokta.

    KURALLAR:
    1. Her noktanın bir 'label' değeri (Harf, Sayı, Kelime veya Emoji) olmalıdır.
    2. 'points' listesinde X ve Y koordinatları 5-95 arasında, birbirine çok yakın olmayacak şekilde dağıtılmalıdır.
    3. Disleksi dostu olması için harfleri b-d-p-q gibi karıştırılan çiftlerden seçmeye özen göster.
    4. Görsel (visuals) varyantında 'imagePrompt' alanını İngilizce nesne adı olarak doldur.

    ÇIKTI: JSON formatında bir dizi (array).
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.NUMBER },
                            gridDim: { type: Type.NUMBER },
                            points: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        label: { type: Type.STRING },
                                        x: { type: Type.NUMBER },
                                        y: { type: Type.NUMBER },
                                        imagePrompt: { type: Type.STRING, nullable: true }
                                    },
                                    required: ['label', 'x', 'y']
                                }
                            }
                        },
                        required: ['points']
                    }
                }
            },
            required: ['title', 'instruction', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
};

