export const GeneratorView: React.FC<GeneratorViewProps> = ({ activity, onGenerate, onBack, isLoading, isExpanded = true, onOpenStudentModal }) => {
    const { students, activeStudent, setActiveStudent } = useStudent();

    const [options, setOptions] = useState<GeneratorOptions>({
        mode: 'fast',
        difficulty: 'Orta',
        worksheetCount: 1,
        itemCount: 12,
        gridSize: 4,
        topic: '',
        variant: 'alphabetic',
        case: 'upper',
        fontFamily: 'OpenDyslexic'
    });

    const handleChange = (key: keyof GeneratorOptions, value: any) => {
        setOptions(prev => ({ ...prev, [key]: value }));
    };

    const handleStudentChange = (id: string) => {
        if (id === 'anonymous') {
            setActiveStudent(null);
        } else {
            const student = students.find(s => s.id === id);
            if (student) setActiveStudent(student);
        }
    };

    const renderActivityControls = () => {
        // --- ABC CONNECT ---
        if (activity.id === ActivityType.ABC_CONNECT) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="İçerik Akışı" 
                        value={options.variant || 'alphabetic'} 
                        onChange={(v:any) => handleChange('variant', v)}
                        options={[
                            { value: 'alphabetic', label: 'Alfabetik (A-B-C)' },
                            { value: 'numeric', label: 'Sayısal (1-2-3)' },
                            { value: 'words', label: 'Kelime Takibi (Semantik)' },
                            { value: 'visuals', label: 'Görsel Eşleme (Resim-Harf)' }
                        ]}
                        icon="fa-route"
                    />

                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactSlider label="Nokta Sayısı" value={options.itemCount} onChange={(v:number) => handleChange('itemCount', v)} min={6} max={26} icon="fa-circle-dot" />
                        <CompactToggleGroup 
                            label="Yazı Tipi" 
                            selected={options.fontFamily || 'OpenDyslexic'} 
                            onChange={(v: string) => handleChange('fontFamily', v)} 
                            options={[{ value: 'OpenDyslexic', label: 'DİSLEKSİ' }, { value: 'Lexend', label: 'SADE' }]} 
                        />
                    </div>
                </div>
            );
        }

        // --- READING SUDOKU ---
        if (activity.id === ActivityType.READING_SUDOKU) {
            return (
                <div className="space-y-5 animate-in fade-in duration-300">
                    <CompactSelect 
                        label="İçerik Türü" 
                        value={options.variant || 'letters'} 
                        onChange={(v:any) => handleChange('variant', v)}
                        options={[
                            { value: 'letters', label: 'Harfler (Disleksi Odaklı)' },
                            { value: 'words', label: 'Kelimeler (Tematik)' },
                            { value: 'visuals', label: 'Görsel Semboller' },
                            { value: 'numbers', label: 'Sayısal' }
                        ]}
                        icon="fa-shapes"
                    />
                    <div className="p-3 bg-zinc-50 dark:bg-zinc-800 rounded-xl border border-zinc-100 dark:border-zinc-700 space-y-4">
                        <CompactToggleGroup label="Izgara Boyutu" selected={options.gridSize?.toString() || "4"} onChange={(v: string) => handleChange('gridSize', parseInt(v))} options={[{ value: '4', label: '4x4' }, { value: '6', label: '6x6' }, { value: '9', label: '9x9' }]} />
                    </div>
                </div>
            );
        }
        return null;
    };

    return (
        <div className="flex flex-col h-full bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-700 shadow-xl overflow-hidden w-full transition-all duration-300">
            <div className="px-4 py-3 border-b border-zinc-200 dark:border-zinc-800 bg-zinc-50/50 dark:bg-zinc-900/50 backdrop-blur-sm shrink-0 flex items-center justify-between z-10 h-[60px]">
                <div className="flex items-center gap-3">
                    <button onClick={onBack} className="w-8 h-8 rounded-full hover:bg-zinc-200 dark:hover:bg-zinc-800 flex items-center justify-center text-zinc-500 transition-colors"><i className="fa-solid fa-arrow-left"></i></button>
                    <h3 className="font-bold text-sm dark:text-white truncate max-w-[150px]">{activity.title}</h3>
                </div>
                {isLoading && <i className="fa-solid fa-circle-notch fa-spin text-indigo-500"></i>}
            </div>

            <div className={`flex-1 overflow-y-auto p-4 custom-scrollbar min-h-0 transition-opacity duration-200 ${isExpanded ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                <div className="mb-6 p-4 bg-amber-50 dark:bg-amber-900/10 rounded-[1.5rem] border border-amber-100 dark:border-amber-800/30">
                    <h4 className="text-[10px] font-black text-amber-600 dark:text-amber-500 uppercase tracking-[0.2em] mb-3 flex items-center gap-2"><i className="fa-solid fa-user-graduate"></i> Aktif Öğrenci</h4>
                    <select value={activeStudent?.id || "anonymous"} onChange={(e) => handleStudentChange(e.target.value)} className="w-full p-2.5 bg-white dark:bg-zinc-800 border border-amber-200 dark:border-amber-700 rounded-xl text-sm font-bold outline-none focus:ring-2 ring-amber-500/20">
                        <option value="anonymous">Misafir / Atanmamış</option>
                        {students.map(s => <option key={s.id} value={s.id}>{s.name} ({s.grade})</option>)}
                    </select>
                </div>

                <div className="grid grid-cols-2 gap-3 mb-6">
                    <CompactCounter label="Sayfa" value={options.worksheetCount} onChange={(v: number) => handleChange('worksheetCount', v)} min={1} max={10} icon="fa-copy" />
                    <CompactSelect label="Zorluk" value={options.difficulty} onChange={(v: string) => handleChange('difficulty', v)} options={DIFFICULTY_OPTIONS} icon="fa-gauge-high" />
                </div>

                <div className="border-t border-zinc-100 dark:border-zinc-700 pt-4 mb-4">
                    <h4 className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-4">Etkinlik Ayarları</h4>
                    {renderActivityControls()}
                </div>

                <div className="mt-8 space-y-3">
                    <button onClick={() => onGenerate({ ...options, mode: 'fast' })} disabled={isLoading} className="w-full py-3 bg-zinc-100 dark:bg-zinc-800 hover:bg-zinc-200 dark:hover:bg-zinc-700 text-zinc-800 dark:text-zinc-200 rounded-xl font-bold text-xs transition-all flex items-center justify-center gap-2 border border-zinc-200 dark:border-zinc-700"><i className="fa-solid fa-bolt"></i> Hızlı Üret (Offline)</button>
                    <button onClick={() => onGenerate({ ...options, mode: 'ai' })} disabled={isLoading} className="w-full px-4 py-3.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-xs shadow-lg shadow-indigo-500/20 transition-all flex items-center justify-center gap-2 transform active:scale-95"><i className="fa-solid fa-wand-magic-sparkles"></i> AI ile Üret (Online)</button>
                </div>
            </div>
        </div>
    );
};

