const PEDAGOGICAL_PROMPT = `
ÜST DÜZEY EĞİTİM İÇERİĞİ OLUŞTURMA YÖNERGESİ (PREMIUM KALİTE):
1.  **Rol:** Sen, "Özel Eğitim ve Üstün Yetenekliler" için materyal hazırlayan uzman bir pedagogsun.
2.  **Çıktı:** Sadece geçerli JSON.
3.  **"pedagogicalNote":** Bu alan veli/öğretmen içindir. Etkinliğin hangi spesifik bilişsel beceriyi desteklediğini akademik ama anlaşılır bir dille açıkla.
4.  **"instruction":** Öğrenciye hitap et. Net, motive edici ve anlaşılır ol.
`;

export const generateAbcConnectFromAI = async (options: GeneratorOptions): Promise<AbcConnectData[]> => {
    const { difficulty, worksheetCount, variant = 'alphabetic', itemCount = 12 } = options;

    const variantDesc = {
        'alphabetic': 'A-Z alfabetik sıra (Disleksi fontu ile).',
        'numeric': '1-20 veya 1-100 arası sayısal sıra.',
        'words': 'Birbiriyle semantik ilişkili veya cümle kuran kelimeler.',
        'visuals': 'Nesne görselleri ve onların isimlerinin baş harfleri.'
    }[variant as string] || 'Alfabetik';

    const prompt = `
    [GÖREV: ABC BAĞLAMACA (DOT-TO-DOT) TANISAL ETKİNLİK]
    [ZORLUK: ${difficulty}]
    [VARYANT: ${variantDesc}]
    [ADET: Sayfa başına ${itemCount} nokta/düğüm.]

    KURALLAR:
    1. Her düğümün bir 'label' değeri (Harf, Sayı, Kelime veya Emoji) olmalıdır.
    2. 'points' listesinde X ve Y koordinatları 5-95 arasında, birbirine çok yakın olmayacak şekilde dağıtılmalıdır.
    3. Disleksi dostu: Karıştırılan harf çiftlerine (b-d, p-q) yer vererek ayrıştırma becerisini zorla.
    4. Görsel varyantta 'imagePrompt' alanını İngilizce nesne adı olarak doldur.

    ÇIKTI: JSON dizi formatında.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                puzzles: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.NUMBER },
                            gridDim: { type: Type.NUMBER },
                            points: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        label: { type: Type.STRING },
                                        x: { type: Type.NUMBER },
                                        y: { type: Type.NUMBER },
                                        color: { type: Type.STRING },
                                        imagePrompt: { type: Type.STRING, nullable: true }
                                    },
                                    required: ['label', 'x', 'y']
                                }
                            }
                        },
                        required: ['points']
                    }
                }
            },
            required: ['title', 'instruction', 'puzzles']
        }
    };

    return await generateWithSchema(prompt, schema, 'gemini-3-flash-preview') as Promise<AbcConnectData[]>;
};

