import { GeneratorOptions, AbcConnectData, VisualOddOneOutData, FindTheDifferenceData } from '../../types';
import { shuffle, getRandomInt, getRandomItems, turkishAlphabet, EMOJI_MAP } from './helpers';

export const generateOfflineAbcConnect = async (options: GeneratorOptions): Promise<AbcConnectData[]> => {
    const { worksheetCount, difficulty, variant = 'alphabetic', itemCount = 12 } = options;

    const nodeCount = difficulty === 'Başlangıç' ? 8 : (difficulty === 'Orta' ? 12 : 20);

    return Array.from({ length: worksheetCount }, () => {
        const points = [];
        let labels: string[] = [];

        if (variant === 'alphabetic') {
            const alphabet = turkishAlphabet.toLocaleUpperCase('tr').split('');
            labels = alphabet.slice(0, nodeCount);
        } else if (variant === 'numeric') {
            labels = Array.from({length: nodeCount}, (_, i) => (i + 1).toString());
        } else if (variant === 'words') {
            labels = shuffle(['ELMA', 'ARMUT', 'MUZ', 'KİRAZ', 'ÇİLEK', 'ÜZÜM', 'KAVUN', 'KARPUZ', 'ERİK', 'VİŞNE', 'NAR', 'AYVA']).slice(0, nodeCount);
        } else if (variant === 'visuals') {
            labels = shuffle(Object.keys(EMOJI_MAP)).slice(0, nodeCount);
        }

        const gridCells = 25; 
        const usedCells = new Set<number>();

        for (let i = 0; i < labels.length; i++) {
            let cell = getRandomInt(0, gridCells - 1);
            while(usedCells.has(cell)) cell = getRandomInt(0, gridCells - 1);
            usedCells.add(cell);

            const row = Math.floor(cell / 5);
            const col = cell % 5;

            points.push({
                label: labels[i],
                x: (col * 18) + getRandomInt(5, 10),
                y: (row * 18) + getRandomInt(5, 10),
                color: '#000000',
                imagePrompt: variant === 'visuals' ? EMOJI_MAP[labels[i]] : undefined
            });
        }

        return {
            title: "ABC Bağlamaca",
            instruction: variant === 'numeric' ? "Sayıları sırasıyla takip ederek birleştirin." : "Harfleri alfabetik sıraya göre bağlayın.",
            pedagogicalNote: "Ardışıl işlemleme hızı, görsel tarama ve el-göz koordinasyonu gelişimini destekler.",
            puzzles: [{
                id: Date.now(),
                gridDim: 100,
                points
            }]
        };
    });
};

