export const generateOfflineClockReading = async (options: GeneratorOptions): Promise<ClockReadingData[]> => {
    const { worksheetCount, difficulty, variant = 'numeric' } = options;

    const romanMap = ["I", "II", "III", "IV", "V", "VI", "VII", "VIII", "IX", "X", "XI", "XII"];
    const verbalMap = ["BİR", "İKİ", "ÜÇ", "DÖRT", "BEŞ", "ALTI", "YEDİ", "SEKİZ", "DOKUZ", "ON", "ON BİR", "ON İKİ"];
    const alphaMap = ["A", "B", "C", "Ç", "D", "E", "F", "G", "Ğ", "H", "I", "İ"];
    const visualMap = ["🍎", "🚗", "🏠", "⭐", "🎈", "📚", "⚽", "☀️", "🌙", "🌲", "🌺", "🎁"];

    return Array.from({ length: worksheetCount }, () => {
        const clocks = Array.from({ length: 4 }, (_, i) => {
            const hour = getRandomInt(1, 12);
            let minute = 0;

            if (difficulty === 'Orta') minute = getRandomItems([0, 15, 30, 45], 1)[0];
            else if (difficulty === 'Zor' || difficulty === 'Uzman') minute = getRandomInt(0, 11) * 5;

            let labels = Array.from({length: 12}, (_, k) => (k + 1).toString());
            if (variant === 'verbal') labels = verbalMap;
            else if (variant === 'alphabetic') labels = alphaMap;
            else if (variant === 'visual') labels = visualMap;

            const timeStr = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;

            return {
                id: `clk-${Date.now()}-${i}`,
                hour,
                minute,
                displayType: 'analog' as const,
                labels,
                correctAnswer: timeStr,
                targetTimeStr: "........................" // Öğrenci yazacak
            };
        });

        const variantTitle = {
            numeric: 'Sayısal',
            verbal: 'Sözel-Yazılı',
            alphabetic: 'Alfabetik Kodlama',
            visual: 'Görsel-Sembolik'
        }[variant as string] || 'Profesyonel';

        return {
            title: `Saat Atölyesi: ${variantTitle}`,
            variant: variant as any,
            instruction: 'Aşağıdaki analog saatlerin gösterdiği zamanı inceleyin. Kadran işaretlerini takip ederek saatin kaç olduğunu altındaki boşluklara yazın.',
            pedagogicalNote: 'Bu çalışma; uzamsal oryantasyon, sayı sembol eşleştirmesi ve ardışıl işlemleme becerilerini disleksi dostu bir mizanpajla destekler.',
            clocks
        };
    });
};

