// --- ENRICHED ANALOG CLOCK FOR DISLEXIA ---
const ProfessionalClock: React.FC<{ hour: number, minute: number, labels: string[], fontSize?: string }> = ({ hour, minute, labels, fontSize = "7" }) => {
    const radius = 45;
    const center = 50;
    const minuteAngle = minute * 6;
    const hourAngle = ((hour % 12) + minute / 60) * 30;

    return (
        <svg viewBox="0 0 100 100" className="w-48 h-48 drop-shadow-md">
            <circle cx={center} cy={center} r={radius} fill="white" stroke="black" strokeWidth="2.5" />
            {/* Hour Markers */}
            {labels.map((label, i) => {
                const angle = ((i + 1) * 30 - 90) * (Math.PI / 180);
                const x = center + (radius - 8) * Math.cos(angle);
                const y = center + (radius - 8) * Math.sin(angle);
                return (
                    <text 
                        key={i} x={x} y={y} 
                        textAnchor="middle" dominantBaseline="middle" 
                        fontSize={fontSize} fontWeight="900" fill="black"
                        className="font-dyslexic"
                    >
                        {label}
                    </text>
                );
            })}
            {/* Minute Ticks */}
            {Array.from({length: 60}).map((_, i) => (
                <line 
                    key={i}
                    x1={center + (radius - 2) * Math.cos((i * 6) * Math.PI / 180)}
                    y1={center + (radius - 2) * Math.sin((i * 6) * Math.PI / 180)}
                    x2={center + (radius - (i % 5 === 0 ? 5 : 2)) * Math.cos((i * 6) * Math.PI / 180)}
                    y2={center + (radius - (i % 5 === 0 ? 5 : 2)) * Math.sin((i * 6) * Math.PI / 180)}
                    stroke={i % 5 === 0 ? "black" : "#ccc"}
                    strokeWidth={i % 5 === 0 ? "1" : "0.5"}
                />
            ))}
            {/* Hands */}
            <line x1={center} y1={center} x2={center + (radius - 12) * Math.cos((minuteAngle - 90) * Math.PI / 180)} y2={center + (radius - 12) * Math.sin((minuteAngle - 90) * Math.PI / 180)} stroke="black" strokeWidth="2.5" strokeLinecap="round" />
            <line x1={center} y1={center} x2={center + (radius - 22) * Math.cos((hourAngle - 90) * Math.PI / 180)} y2={center + (radius - 22) * Math.sin((hourAngle - 90) * Math.PI / 180)} stroke="#4f46e5" strokeWidth="4" strokeLinecap="round" />
            <circle cx={center} cy={center} r="3" fill="black" />
        </svg>
    );
};

