export const generateSyllableStudioFromAI = async (options: GeneratorOptions): Promise<SyllableStudioData[]> => {
    const { difficulty, worksheetCount, variant = 'segmentation', itemCount = 8, topic } = options;

    const variantMap: Record<string, string> = {
        'segmentation': 'Kelimeleri hecelerine ayırma (Ay-na).',
        'blending': 'Ayrılmış heceleri birleştirerek kelime yazma.',
        'completion': 'Yarısı verilmiş kelimeyi hece ile tamamlama.',
        'colored': 'Her hecesi farklı renkte yazılmış kelimeler.',
        'scrambled': 'Karışık verilmiş hecelerden anlamlı kelime türetme.'
    };

    const prompt = `
    [GÖREV: HECE STÜDYOSU - FONOLOJİK FARKINDALIK ETKİNLİĞİ]
    MOD: ${variantMap[variant as string]}
    ZORLUK: ${difficulty}.
    ADET: Sayfa başına ${itemCount} kelime.
    KONU: ${topic || 'Genel Kelimeler'}.

    KURALLAR:
    1. Kelimeler kesinlikle TÜRKÇE heceleme kurallarına göre hecelenmelidir.
    2. 'segmentation' modunda kelime tam, 'syllables' dizisi ayrı olmalı.
    3. 'completion' modunda 'displayPart' görünen, 'missingPart' gizli hece olmalı.
    4. 'colored' modunda her hece için zıt/canlı hex renk kodları ver.
    5. 'scrambled' modunda 'scrambledSyllables' dizisinde heceleri karıştır.
    6. Her kelime için sevimli bir "imagePrompt" ekle.

    ÇIKTI: JSON dizi formatında.
    `;

    const schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                title: { type: Type.STRING },
                instruction: { type: Type.STRING },
                pedagogicalNote: { type: Type.STRING },
                items: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.STRING },
                            word: { type: Type.STRING },
                            syllables: { type: Type.ARRAY, items: { type: Type.STRING } },
                            displayPart: { type: Type.STRING },
                            missingPart: { type: Type.STRING },
                            scrambledSyllables: { type: Type.ARRAY, items: { type: Type.STRING } },
                            colors: { type: Type.ARRAY, items: { type: Type.STRING } },
                            imagePrompt: { type: Type.STRING }
                        },
                        required: ['word', 'syllables']
                    }
                }
            },
            required: ['title', 'items', 'instruction']
        }
    };

    const result = await generateWithSchema(prompt, schema, 'gemini-3-flash-preview');
    return result.map((p: any) => ({
        ...p,
        variant: variant as SyllableStudioVariant,
        settings: {
            fontFamily: options.fontFamily || 'OpenDyslexic',
            letterCase: options.case || 'upper',
            showImages: true
        }
    }));
};
