import { SyllableStudioData, SyllableStudioVariant } from '../../types';
import { simpleSyllabify, getWordsForDifficulty } from './helpers';

export const generateOfflineSyllableStudio = async (options: GeneratorOptions): Promise<SyllableStudioData[]> => {
    const { worksheetCount, difficulty, variant = 'segmentation', itemCount = 8, topic } = options;

    const pool = getWordsForDifficulty(difficulty, topic);
    const colors = ['#ef4444', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899'];

    return Array.from({ length: worksheetCount }, () => {
        const selected = getRandomItems(pool, itemCount || 8);
        const items = selected.map((word, idx) => {
            const syllables = simpleSyllabify(word);
            const res: any = {
                id: `syl-${idx}-${Date.now()}`,
                word: word.toLocaleUpperCase('tr'),
                syllables: syllables.map(s => s.toLocaleUpperCase('tr')),
                imagePrompt: word
            };

            if (variant === 'completion') {
                res.displayPart = res.syllables[0];
                res.missingPart = res.syllables.slice(1).join('');
            } else if (variant === 'scrambled') {
                res.scrambledSyllables = shuffle([...res.syllables]);
            } else if (variant === 'colored') {
                res.colors = res.syllables.map((_, i) => colors[i % colors.length]);
            }

            return res;
        });

        return {
            title: "Hece Stüdyosu",
            instruction: variant === 'segmentation' ? "Kelimeleri hecelerine ayırarak kutucuklara yazın." :
                        variant === 'blending' ? "Heceleri birleştirerek anlamlı kelimeyi oluşturun." :
                        variant === 'scrambled' ? "Karışık hecelerden anlamlı kelimeler türetin." :
                        "Hecelerle ilgili yönergeleri takip edin.",
            pedagogicalNote: "Fonolojik ayrıştırma, işleyen bellek ve sentez becerilerini geliştirir.",
            variant: variant as SyllableStudioVariant,
            items,
            settings: {
                fontFamily: options.fontFamily || 'OpenDyslexic',
                letterCase: options.case || 'upper',
                showImages: true
            }
        };
    });
};
