const CompactSelect = ({ label, value, onChange, options, icon }: any) => (
    <div className="space-y-1.5">
        <label className="text-[10px] font-bold text-zinc-500 dark:text-zinc-400 uppercase flex items-center gap-1.5 px-1 tracking-wider">
            {icon && <i className={`fa-solid ${icon} opacity-50`}></i>}
            {label}
        </label>
        <div className="relative">
            <select 
                value={value} 
                onChange={(e) => onChange(e.target.value)}
                className="w-full h-10 px-4 bg-white dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-700 rounded-xl text-xs font-black text-zinc-700 dark:text-zinc-200 outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all cursor-pointer appearance-none"
            >
                {options.map((opt: any) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
            </select>
            <i className="fa-solid fa-chevron-down absolute right-3 top-1/2 -translate-y-1/2 text-[10px] text-zinc-400 pointer-events-none"></i>
        </div>
    </div>
);

const CompactCounter = ({ label, value, onChange, min, max, icon }: any) => (
    <div className="flex items-center justify-between py-1">
        <label className="text-[10px] font-bold text-zinc-500 dark:text-zinc-400 uppercase flex items-center gap-1.5 tracking-wider">
            {icon && <i className={`fa-solid ${icon} opacity-50`}></i>}
            {label}
        </label>
        <div className="flex items-center bg-white dark:bg-zinc-900 p-1 rounded-xl border border-zinc-100 dark:border-zinc-800 shadow-sm">
            <button 
                onClick={() => onChange(Math.max(min, value - 1))} 
                className="w-7 h-7 flex items-center justify-center text-zinc-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-zinc-800 rounded-lg transition-all"
                disabled={value <= min}
            >
                <i className="fa-solid fa-minus text-[10px]"></i>
            </button>
            <span className="text-xs font-black w-6 text-center text-zinc-800 dark:text-zinc-100 font-mono">{value}</span>
            <button 
                onClick={() => onChange(Math.min(max, value + 1))} 
                className="w-7 h-7 flex items-center justify-center text-zinc-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-zinc-800 rounded-lg transition-all"
                disabled={value >= max}
            >
                <i className="fa-solid fa-plus text-[10px]"></i>
            </button>
        </div>
    </div>
);

const CompactToggleGroup = ({ label, selected, onChange, options, icon }: any) => (
    <div className="space-y-1.5">
        <label className="text-[10px] font-bold text-zinc-500 dark:text-zinc-400 uppercase flex items-center gap-1.5 px-1 tracking-wider">
            {icon && <i className={`fa-solid ${icon} opacity-50`}></i>}
            {label}
        </label>
        <div className="flex bg-zinc-100 dark:bg-zinc-900 p-1 rounded-xl gap-1 border border-zinc-200/50 dark:border-zinc-800">
            {options.map((opt: any) => (
                <button
                    key={opt.value}
                    onClick={() => onChange(opt.value)}
                    className={`flex-1 py-2 text-[9px] font-black rounded-lg transition-all transform active:scale-95 ${selected === opt.value ? 'bg-white dark:bg-zinc-700 text-indigo-600 dark:text-indigo-400 shadow-sm ring-1 ring-black/5' : 'text-zinc-500 hover:text-zinc-700 dark:hover:text-zinc-300'}`}
                >
                    {opt.label}
                </button>
            ))}
        </div>
    </div>
);

export const GeneratorView: React.FC<GeneratorViewProps> = ({ activity, onGenerate, onBack, isLoading, isExpanded = true, onOpenStudentModal, studentProfile }) => {
