                          </div>
                          <div className="flex-1 text-left min-w-0">
                              <p className="text-[10px] font-black text-zinc-400 uppercase tracking-tighter leading-none mb-1">Öğrenci Profili</p>
                              <p className={`text-xs font-black truncate ${studentProfile ? 'text-amber-700 dark:text-amber-400' : 'text-zinc-500 italic'}`}>
                                  {studentProfile ? studentProfile.name : 'Misafir (Seçilmedi)'}
                              </p>
                          </div>
                          <i className="fa-solid fa-chevron-right text-[10px] text-zinc-300"></i>
                      </button>
                  )}

                  <div className="space-y-6">
                      <h4 className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.2em] flex items-center gap-2 border-b border-indigo-50 dark:border-indigo-900/30 pb-2">
